export const getAgeRange = (serie: SerieEscolar): string => {
  const map: Record<SerieEscolar, string> = {
    "1_ano_fundamental": "6-7 anos",
    "2_ano_fundamental": "7-8 anos",
    "3_ano_fundamental": "8-9 anos",
    "4_ano_fundamental": "9-10 anos",
    "5_ano_fundamental": "10-11 anos",
    "6_ano_fundamental": "11-12 anos",
    "7_ano_fundamental": "12-13 anos",
    "8_ano_fundamental": "13-14 anos",
    "9_ano_fundamental": "14-15 anos",
    "1_serie_medio": "15-16 anos",
    "2_serie_medio": "16-17 anos",
    "3_serie_medio": "17-18 anos",
  };
  return map[serie];
};

export const getSchoolLevel = (serie: SerieEscolar): string => {
  if (serie.includes("fundamental")) {
    const num = parseInt(serie.split("_")[0]);
    return num <= 5 ? "Fundamental I" : "Fundamental II";
  }
  return "Ensino Médio";
};

import { Exam } from '../types/exam';
import { GeminiConfig } from '../types/settings';

const EXAMS_KEY = 'eduquest-exams';
const CONFIG_KEY = 'eduquest-gemini-config';

export const storageService = {
  saveExam: (exam: Exam): void => {
    const exams = storageService.getExams();
    const existingIndex = exams.findIndex(e => e.id === exam.id);
    if (existingIndex > -1) {
      exams[existingIndex] = exam;
    } else {
      exams.push(exam);
    }
    localStorage.setItem(EXAMS_KEY, JSON.stringify(exams));
  },

  getExams: (): Exam[] => {
    const data = localStorage.getItem(EXAMS_KEY);
    return data ? JSON.parse(data) : [];
  },

  getExamById: (id: string): Exam | undefined => {
    return storageService.getExams().find(e => e.id === id);
  },

  deleteExam: (id: string): void => {
    const exams = storageService.getExams().filter(e => e.id !== id);
    localStorage.setItem(EXAMS_KEY, JSON.stringify(exams));
  },

  saveGeminiConfig: (config: GeminiConfig): void => {
    localStorage.setItem(CONFIG_KEY, JSON.stringify(config));
  },

  getGeminiConfig: (): GeminiConfig | null => {
    const data = localStorage.getItem(CONFIG_KEY);
    return data ? JSON.parse(data) : null;
  }
};

import { SerieEscolar } from '../types/exam';
import { serieLabels, getAgeRange } from './seriesUtils';

interface PromptParams {
  serie: SerieEscolar;
  disciplina: string;
  objetivo: string;
  conteudoBase: string[];
  nivelDificuldade: "baixa" | "media" | "alta";
}

export const buildExamGenerationPrompt = (params: PromptParams): string => {
  const { serie, disciplina, objetivo, conteudoBase, nivelDificuldade } = params;
  const label = serieLabels[serie];
  const age = getAgeRange(serie);

  return `Aja como um professor especialista brasileiro criando uma prova de ESTUDO para alunos do ${label} (faixa etária aproximada: ${age}).
A disciplina é "${disciplina}".
O objetivo pedagógico é: "${objetivo}".
Nível de dificuldade desejado: ${nivelDificuldade}.

USE O SEGUINTE CONTEÚDO BASE COMO REFERÊNCIA PRINCIPAL:
---
${conteudoBase.join('\n\n')}
---

INSTRUÇÕES IMPORTANTES:
1. Gere EXATAMENTE 40 questões de múltipla escolha.
2. Siga o estilo ENEM: enunciados contextualizados, interdisciplinares onde possível e foco em competências.
3. Cada questão deve ter exatamente 5 alternativas (A, B, C, D, E).
4. Apenas uma alternativa está correta.
5. Para cada questão, escreva uma "explicacao" detalhada que ajude o aluno a aprender o conceito por trás da resposta correta e por que as outras estão erradas (orientação de estudo).
6. Use linguagem e vocabulário adequados para a idade de ${age}.
7. Retorne o resultado estritamente no formato JSON solicitado.
8. Garanta que cada questão tenha um ID único.

Sua resposta deve ser um objeto JSON contendo uma lista de 'questions'.`;
};

import { GoogleGenAI, Type } from "@google/genai";
import { Exam, Question, SerieEscolar } from "../types/exam";
import { buildExamGenerationPrompt } from "../utils/examGenerationPromptBuilder";

interface GenerateParams {
  serie: SerieEscolar;
  disciplina: string;
  objetivo: string;
  conteudoBase: string[];
  nivelDificuldade: "baixa" | "media" | "alta";
  apiKey: string;
  modelName: string;
}

export async function generateExamWithGemini(params: GenerateParams): Promise<Partial<Exam>> {
  const ai = new GoogleGenAI({ apiKey: params.apiKey });
  const prompt = buildExamGenerationPrompt(params);

  const response = await ai.models.generateContent({
    model: params.modelName || 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          questions: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                enunciado: { type: Type.STRING },
                alternativas: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      id: { type: Type.STRING },
                      label: { type: Type.STRING, description: "A, B, C, D ou E" },
                      texto: { type: Type.STRING }
                    },
                    required: ["id", "label", "texto"]
                  }
                },
                alternativaCorretaId: { type: Type.STRING, description: "O ID da alternativa correta" },
                explicacao: { type: Type.STRING },
                competenciaOuHabilidade: { type: Type.STRING }
              },
              required: ["id", "enunciado", "alternativas", "alternativaCorretaId", "explicacao"]
            }
          }
        },
        required: ["questions"]
      }
    }
  });

  const resultText = response.text;
  if (!resultText) {
    throw new Error("Não foi possível obter resposta do Gemini.");
  }

  const parsed = JSON.parse(resultText);
  return {
    questions: parsed.questions as Question[],
    createdAt: new Date().toISOString()
  };
}

import React, { createContext, useContext, useState, useEffect } from 'react';
import { GeminiConfig } from '../types/settings';
import { storageService } from '../services/storageService';
import { AppMode } from '../types/exam';

interface GeminiConfigContextType {
  config: GeminiConfig;
  setConfig: (config: GeminiConfig) => void;
  appMode: AppMode;
  setAppMode: (mode: AppMode) => void;
  isConfigured: boolean;
}

const GeminiConfigContext = createContext<GeminiConfigContextType | undefined>(undefined);

export const GeminiConfigProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [config, setConfigState] = useState<GeminiConfig>({
    apiKey: '',
    model: 'gemini-3-flash-preview'
  });
  const [appMode, setAppMode] = useState<AppMode>('professor');

  useEffect(() => {
    const saved = storageService.getGeminiConfig();
    if (saved) {
      setConfigState(saved);
    }
  }, []);

  const setConfig = (newConfig: GeminiConfig) => {
    setConfigState(newConfig);
    storageService.saveGeminiConfig(newConfig);
  };

  const isConfigured = !!config.apiKey;

  return (
    <GeminiConfigContext.Provider value={{ config, setConfig, appMode, setAppMode, isConfigured }}>
      {children}
    </GeminiConfigContext.Provider>
  );
};

export const useGeminiConfig = () => {
  const context = useContext(GeminiConfigContext);
  if (!context) {
    throw new Error("useGeminiConfig must be used within a GeminiConfigProvider");
  }
  return context;
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost' | 'danger' | 'outline';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  ...props 
}) => {
  const baseStyles = "px-4 py-2 rounded-lg font-medium transition-all duration-200 flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-indigo-600 text-white hover:bg-indigo-700 shadow-sm",
    secondary: "bg-emerald-600 text-white hover:bg-emerald-700 shadow-sm",
    ghost: "bg-transparent text-slate-600 hover:bg-slate-100",
    danger: "bg-red-600 text-white hover:bg-red-700 shadow-sm",
    outline: "bg-transparent border border-indigo-600 text-indigo-600 hover:bg-indigo-50"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`} 
      disabled={isLoading || props.disabled}
      {...props}
    >
      {isLoading ? (
        <svg className="animate-spin h-5 w-5 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      ) : null}
      {children}
    </button>
  );
};

