export const subjectsByGrade: Record<string, string[]> = {
  fundamental_1: [
    "Português", "Matemática", "Ciências", "História", "Geografia", "Artes", "Educação Física", "Inglês"
  ],
  fundamental_2: [
    "Língua Portuguesa", "Matemática", "Ciências Naturais", "História", "Geografia", "Inglês", "Artes", "Educação Física", "Ensino Religioso"
  ],
  medio: [
    "Língua Portuguesa", "Literatura", "Redação", "Matemática", "Biologia", "Física", "Química", "História", "Geografia", "Sociologia", "Filosofia", "Língua Inglesa", "Artes"
  ]
};

export const getSubjectsForSerie = (serie: SerieEscolar): string[] => {
  if (serie.includes("fundamental")) {
    const year = parseInt(serie.split("_")[0]);
    return year <= 5 ? subjectsByGrade.fundamental_1 : subjectsByGrade.fundamental_2;
  }
  return subjectsByGrade.medio;
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { AppMode, UserProfile } from '../types/exam';

interface AppContextType {
  appMode: AppMode;
  userName: string;
  userProfile: UserProfile | null;
  login: (profile: UserProfile) => void;
  logout: () => void;
  selectedModel: string;
  setSelectedModel: (model: string) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const GeminiConfigProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [selectedModel, setSelectedModel] = useState('gemini-3-flash-preview');

  useEffect(() => {
    const saved = localStorage.getItem('eduquest-user-profile');
    if (saved) {
      setUserProfile(JSON.parse(saved));
    }
  }, []);

  const login = (profile: UserProfile) => {
    setUserProfile(profile);
    localStorage.setItem('eduquest-user-profile', JSON.stringify(profile));
  };

  const logout = () => {
    setUserProfile(null);
    localStorage.removeItem('eduquest-user-profile');
  };

  return (
    <AppContext.Provider value={{ 
      appMode: userProfile?.role || 'professor', 
      userName: userProfile?.name || '',
      userProfile,
      login,
      logout,
      selectedModel, 
      setSelectedModel 
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useGeminiConfig = () => {
  const context = useContext(AppContext);
  if (!context) {
    throw new Error("useGeminiConfig must be used within a GeminiConfigProvider");
  }
  return context;
};

